// Este script calcula la fecha de mañana y establece la hora a 12:00.

// Obtener la fecha y hora actual
const hoy = new Date();

// Crear un objeto de fecha para mañana
// Nota: Usamos la hora UTC para evitar problemas con cambios de horario de verano,
// y luego ajustamos la hora local.
const manana = new Date(hoy);
manana.setDate(hoy.getDate() + 1); // Sumar un día

// Establecer la hora a las 12:00:00 (mediodía) en la zona horaria local
manana.setHours(12, 0, 0, 0);

// Función de ayuda para formatear a YYYY-MM-DD
function formatDate(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
}

// Formatear los resultados
const fechaManana = formatDate(manana); // Ej: 2025-12-14
const horaManana = '12:00';

// Devolver un objeto JSON que puedes usar en nodos subsiguientes
return [
  {
    json: {
      manana_fecha_completa: `${fechaManana} ${horaManana}`,
      manana_fecha_solo: fechaManana,
      manana_hora_solo: horaManana
    }
  }
];

